import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../services/api';

interface Task {
  _id: string;
  title: string;
  description: string;
  status: string;
  priority: string;
  assignee: { _id: string; name: string } | null;
  project: { _id: string; name: string };
  dependsOn: { _id: string; title: string; status: string }[];
  blockedBy: { _id: string; title: string; status: string }[];
  dueDate: string;
  estimatedHours: number;
  createdAt: string;
}

interface User {
  _id: string;
  name: string;
  email: string;
}

const TaskDetails = () => {
  const { taskId } = useParams<{ taskId: string }>();
  const navigate = useNavigate();
  const [task, setTask] = useState<Task | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [dependsOnId, setDependsOnId] = useState('');

  useEffect(() => {
    fetchTask();
    fetchUsers();
  }, [taskId]);

  const fetchTask = async () => {
    try {
      setLoading(true);
      // Get all tasks from project and find this one
      const response = await api.get(`/tasks/project/${task?.project?._id}`);
      const found = response.data.data.find((t: Task) => t._id === taskId);
      setTask(found);
    } catch (err: any) {
      setError(err.response?.data?.message || 'Failed to load task');
    } finally {
      setLoading(false);
    }
  };

  const fetchUsers = async () => {
    try {
      const response = await api.get('/users');
      setUsers(response.data.data || []);
    } catch (err) {
      console.error('Failed to load users');
    }
  };

  const addDependency = async () => {
    if (!dependsOnId || !taskId) return;
    try {
      await api.post('/tasks/dependency', {
        taskId,
        dependsOnId
      });
      setDependsOnId('');
      fetchTask();
    } catch (err: any) {
      alert(err.response?.data?.message || 'Failed to add dependency');
    }
  };

  if (loading) {
    return <div style={styles.loading}>Loading task details...</div>;
  }

  if (error || !task) {
    return <div style={styles.error}>{error || 'Task not found'}</div>;
  }

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <button onClick={() => navigate(`/project/${task.project._id}`)} style={styles.backBtn}>
          ← Back to Project
        </button>
        <h1 style={styles.title}>{task.title}</h1>
      </header>

      <div style={styles.content}>
        <div style={styles.detailsCard}>
          <div style={styles.detailRow}>
            <span style={styles.label}>Status:</span>
            <span style={{
              ...styles.statusBadge,
              backgroundColor: {
                todo: '#6c757d',
                in_progress: '#0066cc',
                in_review: '#ffc107',
                done: '#28a745',
                blocked: '#dc3545'
              }[task.status]
            }}>
              {task.status}
            </span>
          </div>

          <div style={styles.detailRow}>
            <span style={styles.label}>Priority:</span>
            <span style={{
              ...styles.priorityBadge,
              backgroundColor: {
                low: '#6c757d',
                medium: '#ffc107',
                high: '#fd7e14',
                critical: '#dc3545'
              }[task.priority]
            }}>
              {task.priority}
            </span>
          </div>

          <div style={styles.detailRow}>
            <span style={styles.label}>Assignee:</span>
            <span>{task.assignee?.name || 'Unassigned'}</span>
          </div>

          <div style={styles.detailRow}>
            <span style={styles.label}>Due Date:</span>
            <span>{task.dueDate ? new Date(task.dueDate).toLocaleDateString() : 'Not set'}</span>
          </div>

          <div style={styles.detailRow}>
            <span style={styles.label}>Estimated Hours:</span>
            <span>{task.estimatedHours || 0}h</span>
          </div>

          <div style={styles.detailRow}>
            <span style={styles.label}>Created:</span>
            <span>{new Date(task.createdAt).toLocaleDateString()}</span>
          </div>

          <div style={styles.descriptionSection}>
            <h3>Description</h3>
            <p>{task.description || 'No description provided'}</p>
          </div>
        </div>

        <div style={styles.dependenciesCard}>
          <h3>Dependencies</h3>
          
          <div style={styles.addDependency}>
            <select
              value={dependsOnId}
              onChange={(e) => setDependsOnId(e.target.value)}
              style={styles.select}
            >
              <option value="">Select a task...</option>
              {/* Would need to fetch all tasks in project */}
            </select>
            <button onClick={addDependency} style={styles.addDepBtn}>
              Add Dependency
            </button>
          </div>

          {task.dependsOn && task.dependsOn.length > 0 ? (
            <ul style={styles.depList}>
              {task.dependsOn.map(dep => (
                <li key={dep._id} style={styles.depItem}>
                  <span>{dep.title}</span>
                  <span style={{
                    ...styles.depStatus,
                    color: dep.status === 'done' ? '#28a745' : '#ffc107'
                  }}>
                    {dep.status}
                  </span>
                </li>
              ))}
            </ul>
          ) : (
            <p style={styles.noDeps}>No dependencies</p>
          )}

          {task.blockedBy && task.blockedBy.length > 0 && (
            <>
              <h4 style={styles.blockedTitle}>Blocked By</h4>
              <ul style={styles.depList}>
                {task.blockedBy.map(block => (
                  <li key={block._id} style={styles.depItem}>
                    <span>{block.title}</span>
                    <span style={{
                      ...styles.depStatus,
                      color: block.status === 'done' ? '#28a745' : '#dc3545'
                    }}>
                      {block.status}
                    </span>
                  </li>
                ))}
              </ul>
            </>
          )}
        </div>

        <div style={styles.actionsCard}>
          <h3>Actions</h3>
          <div style={styles.actionButtons}>
            {['todo', 'in_progress', 'in_review', 'done', 'blocked'].map(status => (
              <button
                key={status}
                onClick={() => {
                  api.put(`/tasks/${task._id}/status`, { status })
                    .then(() => fetchTask())
                    .catch(err => alert(err.response?.data?.message || 'Failed'));
                }}
                style={{
                  ...styles.actionBtn,
                  backgroundColor: task.status === status ? '#0066cc' : '#e9ecef',
                  color: task.status === status ? 'white' : '#333'
                }}
              >
                {status.replace('_', ' ')}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

